### Option 1: Web-Based 3D House with Three.js

This example creates a simple 3D house using Three.js in a web browser.

```html
<!DOCTYPE html>
<html>
<head>
  <title>3D House</title>
  <style>
    body { margin: 0; }
    canvas { display: block; }
  </style>
</head>
<body>
  <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
  <script>
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
    const renderer = new THREE.WebGLRenderer();
    renderer.setSize(window.innerWidth, window.innerHeight);
    document.body.appendChild(renderer.domElement);

    // House materials
    const wallMaterial = new THREE.MeshLambertMaterial({ color: 0x888888 });
    const roofMaterial = new THREE.MeshLambertMaterial({ color: 0x8B4513 });
    const windowMaterial = new THREE.MeshLambertMaterial({ color: 0xADD8E6 });

    // House body
    const house = new THREE.Mesh(new THREE.BoxGeometry(4, 3, 4), wallMaterial);
    scene.add(house);

    // Roof
    const roof = new THREE.Mesh(new THREE.ConeGeometry(3, 2, 4), roofMaterial);
    roof.position.y = 4.5;
    scene.add(roof);

    // Windows
    const windowGeometry = new THREE.BoxGeometry(1, 1, 0.1);
    const window1 = new THREE.Mesh(windowGeometry, windowMaterial);
    window1.position.set(1, 1.5, 2);
    scene.add(window1);

    const window2 = new THREE.Mesh(windowGeometry, windowMaterial);
    window2.position.set(-1, 1.5, 2);
    scene.add(window2);

    // Lighting
    const ambientLight = new THREE.AmbientLight(0x404040);
    scene.add(ambientLight);
    const directionalLight = new THREE.DirectionalLight(0xffffff, 1);
    directionalLight.position.set(5, 10, 7);
    scene.add(directionalLight);

    // Camera position
    camera.position.set(5, 5, 5);
    camera.lookAt(0, 0, 0);

    // Animation loop
    function animate() {
      requestAnimationFrame(animate);
      renderer.render(scene, camera);
    }
    animate();

    // Handle window resize
    window.addEventListener('resize', () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    });
  </script>
</body>
</html>
```

