### Option 3: Blender Python Script

This script generates a basic 3D house using Blender's Python API.

```python
import bpy

# Clear existing objects
for obj in bpy.data.objects:
    bpy.data.objects.remove(obj, do_unlink=True)

# Create house body
bpy.ops.mesh.primitive_cube_add(size=2, location=(0, 0, 0))
house = bpy.context.active_object
house.name = "House"
house.scale = (4, 4, 3)

# Create roof
bpy.ops.mesh.primitive_cone_add(radius1=2, depth=2, location=(0, 0, 4.5))
roof = bpy.context.active_object
roof.name = "Roof"
roof.rotation_euler = (0, 0, 0)

# Add windows
for i in range(2):
    bpy.ops.mesh.primitive_cube_add(size=1, location=(i*2, 0, 1.5))
    window = bpy.context.active_object
    window.name = f"Window_{i+1}"
    window.scale = (1, 1, 0.1)

# Add lighting
bpy.ops.object.light_add(type='SUN', location=(5, 5, 10))
sun = bpy.context.active_object
sun.name = "Sun"

# Add camera
bpy.ops.object.camera_add(location=(5, 5, 5))
camera = bpy.context.active_object
camera.name = "Camera"
camera.rotation_euler = (0, 0, 0)

# Save scene
bpy.ops.wm.save_as_mainfile(filepath="/path/to/house.blend")
```

